// ─── Helper functions ──────────────────────────────────────────────────────────

export function getBlock(id: string): Block | undefined {
  return BLOCKS.find(b => b.id === id)
}

export function getModulesByBlock(blockId: string): Module[] {
  return MODULES.filter(m => m.blockId === blockId).sort((a, b) => a.order - b.order)
}

export function getStudiesByModule(moduleId: string): Study[] {
  return STUDIES.filter(s => s.moduleId === moduleId).sort((a, b) => a.order - b.order)
}

export function getStudy(id: string): Study | undefined {
  const study = STUDIES.find(s => s.id === id)
  if (!study) return undefined
  const content = STUDY_CONTENT[id] ?? study.content
  return content ? { ...study, content } : study
}

export const TOTAL_STUDIES = STUDIES.length
